using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed: Cosmos DB indexing is managed via the container's
        // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
        // In EF Core 9 calling HasIndex on a Cosmos entity throws at startup.

        // Preserve "Discriminator" property name used by existing documents
        // (EF Core 9 defaults to "$type").
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Preserve the compound id format "Blog|1" used by existing documents
        // (EF Core 9 defaults to key-only ids).
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

